    [SupplyParameterFromQuery(Name = "mobile")]
    public string? MobileNumber { get; set; }

    private string? OTP { get; set; }
    private string? Message { get; set; }
    private bool IsSuccess { get; set; }
    private bool IsLoading { get; set; }
    private string? DeviceId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (string.IsNullOrEmpty(MobileNumber))
        {
            Navigation.NavigateTo("/mobile-verification");
        }

        // Try to get device ID from localStorage, else generate and store
        DeviceId = await JS.InvokeAsync<string>("localStorage.getItem", "deviceId");
        if (string.IsNullOrEmpty(DeviceId))
        {
            DeviceId = await JS.InvokeAsync<string>("eval", "crypto.randomUUID ? crypto.randomUUID() : ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c=>(c^crypto.getRandomValues(new Uint8Array(1))[0]&15>>c/4).toString(16))");
            await JS.InvokeVoidAsync("localStorage.setItem", "deviceId", DeviceId);
        }
    }

    private async Task HandleVerifyOTP()
    {
        if (string.IsNullOrWhiteSpace(OTP))
        {
            Message = "Please enter OTP";
            IsSuccess = false;
            return;
        }

        if (string.IsNullOrWhiteSpace(MobileNumber))
        {
            Message = "Mobile number is missing";
            IsSuccess = false;
            return;
        }

        IsLoading = true;
        Message = null;

        // Pass DeviceId to AuthService
        var result = await AuthService.VerifyOTPAsync(MobileNumber, OTP, DeviceId ?? string.Empty);


        if (result.IsSuccess)
        {
            // store companies in service and sessionStorage, then navigate
            await CompanyService.SetCompaniesAsync(result.Companies);
            await UserSession.SetMobileNoAsync(MobileNumber);
            Navigation.NavigateTo("/company-selection");
        }
        else
        {
            Message = result.Message;
            IsSuccess = false;
        }

        IsLoading = false;
    }

    private void GoBack()
    {
        Navigation.NavigateTo("/mobile-verification");
    }

    [Inject]
    private IJSRuntime JS { get; set; } = default!;

